// ---------------------------------------------------------------------------
// BotDiff Champion Knowledge (compact, deterministic)
//
// A small, curated knowledge base used by the Build & Matchup coach. It is NOT
// generated by AI and never invents champion facts — it encodes well-known
// threat tags and ADC build archetypes so recommendations are grounded in the
// real match's champions. Unknown champions simply contribute nothing.
//
// PURE + client-safe.
// ---------------------------------------------------------------------------

export type ThreatTag =
  | "ap"
  | "ad"
  | "cc"
  | "dive"
  | "assassin"
  | "poke"
  | "tank"
  | "engage";

