export function tagsFor(champion: string): ThreatTag[] {
  return CHAMPION_TAGS[champion] ?? [];
}

export interface ThreatProfile {
  known: number;
  total: number;
  ap: number;
  ad: number;
  cc: number;
  dive: number; // assassins + divers
  poke: number;
  tank: number;
  engage: number;
}

export function threatProfile(champions: string[]): ThreatProfile {
  const p: ThreatProfile = { known: 0, total: champions.length, ap: 0, ad: 0, cc: 0, dive: 0, poke: 0, tank: 0, engage: 0 };
  for (const c of champions) {
    const tags = tagsFor(c);
    if (tags.length === 0) continue;
    p.known++;
    if (tags.includes("ap")) p.ap++;
    if (tags.includes("ad")) p.ad++;
    if (tags.includes("cc")) p.cc++;
    if (tags.includes("dive") || tags.includes("assassin")) p.dive++;
    if (tags.includes("poke")) p.poke++;
    if (tags.includes("tank")) p.tank++;
    if (tags.includes("engage")) p.engage++;
  }
  return p;
}

